#!/bin/bash\necho \"=========================================\"\necho \"JENKINS TROUBLESHOOTING DEBUG\"\necho \"=========================================\"\n\necho \"1. Check if Jenkins namespace exists:\"\nkubectl get namespaces | grep jenkins\necho \"\"\n\necho \"2. Check Jenkins pods status:\"\nkubectl get pods -n jenkins -o wide\necho \"\"\n\necho \"3. Check Jenkins service:\"\nkubectl get svc -n jenkins -o wide\necho \"\"\n\necho \"4. Check Jenkins ingress:\"\nkubectl get ingress -n jenkins -o wide\necho \"\"\n\necho \"5. Describe Jenkins ingress (check ALB creation):\"\nkubectl describe ingress jenkins-ingress -n jenkins\necho \"\"\n\necho \"6. Check ALB Controller pods:\"\nkubectl get pods -n kube-system | grep aws-load-balancer-controller\necho \"\"\n\necho \"7. Check ALB Controller logs (last 20 lines):\"\nkubectl logs -n kube-system deployment/aws-load-balancer-controller --tail=20\necho \"\"\n\necho \"8. Check if Jenkins service endpoints are ready:\"\nkubectl get endpoints -n jenkins\necho \"\"\n\necho \"9. Test Jenkins service internally:\"\necho \"Port-forward command: kubectl port-forward -n jenkins svc/jenkins 8080:8080\"\necho \"Then test: curl http://localhost:8080/login\"\necho \"\"\n\necho \"10. Check ingress class:\"\nkubectl get ingressclass\necho \"\"\n\necho \"=========================================\"\necho \"Run this script and share ALL the output\"\necho \"=========================================\"